/// D160 Plan 100.4.3: kind of a defer entry ‚Äî determines which exit paths trigger it.
#[derive(Clone, Copy, PartialEq, Eq)]
enum DeferKind {
    /// Plain `defer` ‚Äî runs on ALL exit paths (normal/return/throw/panic/interrupt).
    Plain,
    /// `errdefer` ‚Äî runs ONLY on error exit (throw/panic). Skip on normal/return/interrupt.
    ErrDefer,
    /// `okdefer` ‚Äî runs ONLY on success exit (normal end-of-scope/return).
    /// Skip on throw/panic/interrupt. Complement to ErrDefer (D160).
    OkDefer,
    /// `defer |result| { ... }` ‚Äî runs on ALL exit paths like `defer`,
    /// but result-binding is available in the body (D160).
    WithResult,
}

/// Plan 20 –§.4: per-defer-stmt entry ‚Äî tracks one `defer { ... }`,
/// `errdefer { ... }`, `okdefer { ... }`, or `defer |result| { ... }` statement.
struct DeferEntry {
    /// C variable name of the `int` activation flag. Initialized to 0
    /// at block start; set to 1 inline at the defer's textual position
    /// (so partial-init exits run only defers that already executed).
    active_var: String,
    /// Kind of this defer entry ‚Äî determines which exit paths it fires on.
    kind: DeferKind,
    /// AST body to re-emit at cleanup point. AST stores defer body as
    /// arbitrary `Expr` (parser wraps `defer { ... }` in ExprKind::Block).
    body: Expr,
}

/// Plan 20 –§.4: per-block defer state. One scope per block that contains
/// at least one defer/errdefer.
///
/// `needs_failframe` / `failframe_var` / `intframe_var` —Å–µ–π—á–∞—Å –Ω–µ —á–∏—Ç–∞—é—Ç—Å—è
/// –Ω–∞–ø—Ä—è–º—É—é (codegen –∏—Å–ø–æ–ª—å–∑—É–µ—Ç `failframe_popped_var` / `intframe_popped_var`
/// + –ø—Ä–æ–≤–µ—Ä–∫–∏ –Ω–∞ `entries.iter().any(_)`), –Ω–æ —Å–æ—Ö—Ä–∞–Ω—è—é—Ç—Å—è –∫–∞–∫ diagnostic
/// metadata + —Ç–æ—á–∫–∏ —Ä–∞—Å—à–∏—Ä–µ–Ω–∏—è –¥–ª—è –±—É–¥—É—â–µ–π debug-–∏–Ω—Ñ—Ä–∞—Å—Ç—Ä—É–∫—Ç—É—Ä—ã.
#[allow(dead_code)]
struct DeferScope {
    /// Unique block ID for naming.
    block_id: usize,
    /// All defer/errdefer entries registered in this block, in textual order.
    /// Cleanup walks this in reverse for LIFO semantics.
    entries: Vec<DeferEntry>,
    /// Running index into `entries` ‚Äî incremented each time emit_stmt
    /// reaches a Defer/ErrDefer and activates its flag.
    next_idx: usize,
    /// `true` if the scope has at least one `errdefer` ‚Äî triggers
    /// NovaFailFrame setjmp wrapper so throw-path can detect error exit.
    needs_failframe: bool,
    /// Name of the C NovaFailFrame variable when `needs_failframe`.
    failframe_var: String,
    /// Name of the C `int` "fail-frame popped" flag (set to 1 by
    /// early-exit cleanup so leave_defer_scope skips the second
    /// `nova_fail_pop()`). Valid when `needs_failframe`.
    failframe_popped_var: String,
    /// Plan 20 –§.8 (2): name of C NovaInterruptFrame variable. Always
    /// present when any defer is in the block ‚Äî defers run on interrupt-
    /// path —Ç–æ–∂–µ (D90 –ø.8).
    intframe_var: String,
    /// Plan 20 –§.8 (2): name of C `int` "interrupt-frame popped" flag
    /// (set to 1 by early-exit cleanup / interrupt-path handler).
    intframe_popped_var: String,
    /// `true` if this scope is loop-body ‚Äî break/continue stop here
    /// rather than walking outer scopes.
    is_loop_body: bool,
}

