            // dedicated C struct –≤ nova_rt/*.h. Codegen —ç–º–∏—Ç–∏—Ç –ø–æ–ª–Ω—É—é
            // typedef + nova_make_ReadBufferError_UnexpectedEnd —á–µ—Ä–µ–∑
            // –æ–±—ã—á–Ω—ã–π emit_sum_type path. Registry –ø–æ–ª—É—á–∏—Ç –¥–≤–µ entries:
            // DeclaredFromUser (–æ—Ç emit_sum_type ‚Üí register_user_sum) +
            // DeclaredFromPrelude (–æ—Ç init_prelude_decls_from_items).
            // Lookup precedence ‚Äî Prelude > User > Hardcoded; both
